python3 -c "
import csv
from datetime import datetime

with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    rows = list(reader)

# Find questions resolving Feb 19-25
upcoming = []
for r in rows:
    if r['is_resolved'] == 'False':
        try:
            res_date = datetime.strptime(r['resolution_date'], '%Y-%m-%d')
            if datetime(2026, 2, 19) <= res_date <= datetime(2026, 2, 25):
                upcoming.append(r)
        except:
            pass

for r in sorted(upcoming, key=lambda x: x['resolution_date']):
    pred = r.get('my_prediction', '')
    print(f\"qid {r['qid']}: {r['title'][:70]}... | Res: {r['resolution_date']} | Pred: {pred[:50] if pred else 'NONE'}...\")
"
